import{_ as i,o as a,c as n,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"3E. Workplace Trainer Careers Advisor","description":"","frontmatter":{"title":"3E. Workplace Trainer Careers Advisor","eba":"Health Allied & Managers Admin 2021-2025","topics":["schedules","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/schedules/3e-workplace-trainer-careers-advisor.md","filePath":"ebas/has-managers-admin/schedules/3e-workplace-trainer-careers-advisor.md"}'),t={name:"ebas/has-managers-admin/schedules/3e-workplace-trainer-careers-advisor.md"};function s(o,e,l,p,d,c){return a(),n("div",null,[...e[0]||(e[0]=[r(`<h1 id="_3e-workplace-trainer-careers-advisor" tabindex="-1">3E. Workplace Trainer Careers Advisor <a class="header-anchor" href="#_3e-workplace-trainer-careers-advisor" aria-label="Permalink to &quot;3E. Workplace Trainer Careers Advisor&quot;">​</a></h1><p>Formatting note</p><p>The schedule body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find schedules by their title, number, topic or synonyms.</p><p>\`\`\`text ADVISOR 1. The Role 1.1 A Workplace Trainer/Careers Advisor will provide essential training and assessment activities – including designing and developing learning programs; using training packages and accredited courses to meet employee needs; planning, organising and delivering group and individual-based learning; facilitating learning in the workplace; and creating, implementing and managing assessment activities and processes.</p><pre><code> 1.2     This role is required to deliver training and assessment services in the health
         industry. They will be required to teach competencies from training packages
         across Certificate II to a Diploma level in classifications covered by the
         Agreement. The position also advises participants in relation to possible career
         pathways, and areas of potential future training and employment.

 1.3     The subjects that the position will deliver are to be determined in conjunction with
         the strategy set by the Agreement Implementation Committee (AIC) which may
         change from time to time.

 1.4     Particular emphasis for training will be given to certain types of individuals,
         including those:
          (a)   without computer skills;
          (b)   who have not completed secondary school education; and,
          (c)   whose English may be a second language.

 1.5     The position may require delivery of evening or weekend classes as determined
         by the needs identified by the Agreement Implementation Committee.
</code></pre><ol><li><p>Duties Duties include:</p><p>2.1 Design learning programs that meet industry expectations and provide meaningful learning experiences.</p><p>2.2 Coordinate and deliver work-based learning using best practice delivery modes.</p><p>2.3 Design and develop learning resources to support the programs and learning outcomes identified by the AIC strategy.</p><p>2.4 Design, develop and evaluate assessment tools for specific purposes including Recognition of Prior Learning (RPL) and assessment of training outcomes.</p><p>2.5 Establish and maintain relationships with all stakeholders (Employers, Employees, and training providers) to ensure learning programs, and related assessment, meet the parties’ needs.</p><p>2.6 Develop approaches to meet compliance requirements and continually improve workplace practice.</p><p>2.7 Liaise with external training providers to deliver appropriate courses to participating employees.</p><p>2.8 Assist participating employees to negotiate leave for the purposes of practical experience and or clinical placements.</p><p>2.9 Provide advice to interested parties in relation to course funding and availability.</p></li><li><p>Qualifications Required qualifications and experience for this role is as follows:</p><p>3.1 TAE40110: Certificate IV in Training and Assessment, or equivalent or the ability to acquire such within the role.</p><p>3.2 Relevant vocational qualification and/or competencies at least to the level to be delivered and assessed.</p><p>3.3 Relevant current industry experience.</p><p>3.4 A valid Working with Children Check (WWC) Assessment Notice and/or WWC card.</p><p>3.5 Clear Police Check.</p></li><li><p>Process for appointment The Employer and the AIC will work together to develop a recruitment process. The Employer will appoint the position taking into account the advice of the AIC. \`\`\`</p></li></ol>`,6)])])}const g=i(t,[["render",s]]);export{h as __pageData,g as default};
